import{_ as a,a as d,b as e}from"./chunks/配置容量限制.DkdWbdOw.js";import{_ as l,o as r,c as o,a2 as i}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"Cloudflare R2 チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/cloudflare-r2.md","filePath":"ja-JP/upload/cloudflare-r2.md","lastUpdated":1781962217000}'),c={name:"ja-JP/upload/cloudflare-r2.md"};function n(h,t,u,s,p,f){return r(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="cloudflare-r2-チャンネルの追加" tabindex="-1">Cloudflare R2 チャンネルの追加 <a class="header-anchor" href="#cloudflare-r2-チャンネルの追加" aria-label="Permalink to &quot;Cloudflare R2 チャンネルの追加&quot;">​</a></h1><p>Cloudflare R2 チャンネルは、Cloudflare の R2 バケットへファイルを保存するための設定です。</p><h2 id="向いているケース" tabindex="-1">向いているケース <a class="header-anchor" href="#向いているケース" aria-label="Permalink to &quot;向いているケース&quot;">​</a></h2><ul><li>Cloudflare Workers と同じ環境でストレージも管理したい。</li><li>R2 バケットを ImgBed の主な保存先にしたい。</li><li>独自ドメインや CDN と組み合わせて画像配信したい。</li></ul><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Cloudflare アカウント</td><td>R2 と API Token を管理します</td></tr><tr><td>R2 バケット</td><td>ファイルの保存先</td></tr><tr><td>Account ID</td><td>R2 操作に必要です</td></tr><tr><td>API Token</td><td>バケットへの読み書きに使います</td></tr><tr><td>カスタムドメイン</td><td>任意。公開 URL を整えたい場合に使います</td></tr></tbody></table><h2 id="バケットを作成する" tabindex="-1">バケットを作成する <a class="header-anchor" href="#バケットを作成する" aria-label="Permalink to &quot;バケットを作成する&quot;">​</a></h2><p>Cloudflare Dashboard で <code>R2 Object Storage</code> を開き、新しいバケットを作成します。</p><p><img src="'+a+'" alt="R2 バケット作成" loading="lazy"></p><p>バケット名はあとで ImgBed に入力するため、正確に控えておきます。</p><h2 id="account-id-を確認する" tabindex="-1">Account ID を確認する <a class="header-anchor" href="#account-id-を確認する" aria-label="Permalink to &quot;Account ID を確認する&quot;">​</a></h2><p>Cloudflare のアカウント画面で Account ID を確認します。</p><p><img src="'+d+'" alt="Account ID" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で「チャンネル追加」を開き、<code>Cloudflare R2</code> を選択します。</p><p>主な項目は次のとおりです。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>自分が識別しやすい名前</td></tr><tr><td>Account ID</td><td>Cloudflare の Account ID</td></tr><tr><td>Bucket 名</td><td>作成した R2 バケット名</td></tr><tr><td>API Token</td><td>R2 へアクセスできる Token</td></tr><tr><td>カスタムドメイン</td><td>任意。設定済みの場合のみ入力</td></tr><tr><td>保存ディレクトリ</td><td>任意。通常は <code>imgbed</code> で問題ありません</td></tr></tbody></table><h2 id="容量制限" tabindex="-1">容量制限 <a class="header-anchor" href="#容量制限" aria-label="Permalink to &quot;容量制限&quot;">​</a></h2><p>必要に応じて容量制限を設定できます。</p><p><img src="'+e+'" alt="容量制限" loading="lazy"></p><p>容量制限を有効にすると、設定した上限やしきい値に応じて、そのチャンネルへの書き込みを調整できます。</p><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><ol><li>保存後に R2 チャンネルカードが表示される。</li><li>チャンネルが有効になっている。</li><li>テスト画像をアップロードする。</li><li>R2 バケットにオブジェクトが作成されている。</li><li>返されたリンクがブラウザで開ける。</li></ol><h2 id="よくある原因" tabindex="-1">よくある原因 <a class="header-anchor" href="#よくある原因" aria-label="Permalink to &quot;よくある原因&quot;">​</a></h2><ul><li>Account ID または Bucket 名が間違っている。</li><li>API Token に対象バケットの権限がない。</li><li>カスタムドメインが R2 バケットに正しく接続されていない。</li><li>容量制限により書き込み対象から外れている。</li></ul>',25)])])}const P=l(c,[["render",n]]);export{_ as __pageData,P as default};
